import{_ as t,o,c as i,ag as a}from"./chunks/framework.YaIgwL5o.js";const u=JSON.parse('{"title":"Export & Sharing","description":"","frontmatter":{},"headers":[],"relativePath":"features/export.md","filePath":"features/export.md"}'),r={name:"features/export.md"};function n(s,e,l,p,h,d){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="export-sharing" tabindex="-1">Export &amp; Sharing <a class="header-anchor" href="#export-sharing" aria-label="Permalink to &quot;Export &amp; Sharing&quot;">​</a></h1><p>Slides Editor supports multiple export formats so you can share your presentation in any context — live on the web, offline at a conference, or embedded in a document.</p><h2 id="html-export-standalone" tabindex="-1">HTML export (standalone) <a class="header-anchor" href="#html-export-standalone" aria-label="Permalink to &quot;HTML export (standalone)&quot;">​</a></h2><p>The default HTML export produces a <strong>self-contained <code>.html</code> file</strong> that loads reveal.js and other assets from a CDN.</p><ul><li>Open your presentation in the editor.</li><li>Click <strong>File → Export → HTML</strong>.</li><li>Save the <code>.html</code> file to your computer.</li><li>Open the file in any browser to present.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Standalone HTML is the smallest file format because assets are fetched from a CDN at runtime. Use it when you expect an internet connection.</p></div><h2 id="offline-html" tabindex="-1">Offline HTML <a class="header-anchor" href="#offline-html" aria-label="Permalink to &quot;Offline HTML&quot;">​</a></h2><p>Offline HTML inlines all external CSS, JavaScript, and font assets so the file works <strong>without any internet connection</strong>.</p><ul><li>Click <strong>File → Export → Offline HTML</strong>.</li><li>The export process downloads all CDN assets and inlines them — this may take a few seconds.</li><li>The resulting file is self-contained and can be copied to a USB drive or shared by email.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use offline HTML when presenting at a conference venue where Wi-Fi may be unreliable, or when distributing slides to students.</p></div><h2 id="pdf" tabindex="-1">PDF <a class="header-anchor" href="#pdf" aria-label="Permalink to &quot;PDF&quot;">​</a></h2><p>Export a <strong>print-ready PDF</strong> using the browser&#39;s print dialog with reveal.js print styles applied.</p><ul><li>Click <strong>File → Export → PDF</strong>.</li><li>The editor opens a print-optimized view in a new tab with all fragments expanded.</li><li>Use <strong>Ctrl+P</strong> (or Cmd+P) and choose &quot;Save as PDF&quot; in the print dialog.</li><li>Set margins to &quot;None&quot; for best results.</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>PDF export relies on the browser&#39;s print engine. Complex layouts, custom fonts, or TikZ diagrams may render slightly differently than on-screen. Check the print preview before finalizing.</p></div><h2 id="pptx-powerpoint" tabindex="-1">PPTX (PowerPoint) <a class="header-anchor" href="#pptx-powerpoint" aria-label="Permalink to &quot;PPTX (PowerPoint)&quot;">​</a></h2><p>Export a <strong>PowerPoint-compatible <code>.pptx</code> file</strong> for editing in Microsoft Office, Google Slides, or LibreOffice Impress.</p><ul><li>Click <strong>File → Export → PPTX</strong>.</li><li>Text, images, and basic shapes are exported as editable PowerPoint elements.</li><li>Complex elements (LaTeX blocks, charts) are rasterized as images in the PPTX.</li></ul><h2 id="shareable-links" tabindex="-1">Shareable links <a class="header-anchor" href="#shareable-links" aria-label="Permalink to &quot;Shareable links&quot;">​</a></h2><p>Generate a <strong>shareable URL</strong> that others can open to view (or edit) your presentation directly in their browser — no installation required.</p><ul><li>Click <strong>Share → Get Link</strong>.</li><li>Choose <strong>View only</strong> or <strong>Editable</strong>.</li><li>Copy and share the URL.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Shareable links require your Slides Editor instance to be accessible from the internet (or your local network). If running locally behind a firewall, share the exported HTML file instead.</p></div><h2 id="github-push" tabindex="-1">GitHub push <a class="header-anchor" href="#github-push" aria-label="Permalink to &quot;GitHub push&quot;">​</a></h2><p>Push your presentation file directly to a <strong>GitHub repository</strong>.</p><ol><li>Click <strong>File → Publish to GitHub</strong>.</li><li>Authenticate with GitHub (OAuth or personal access token).</li><li>Choose the repository and branch.</li><li>Enter a commit message.</li><li>Click <strong>Push</strong>.</li></ol><p>The presentation is saved as a <code>.json</code> file in the repository. You can also push the exported HTML to enable GitHub Pages hosting of your slides.</p>',25)])])}const f=t(r,[["render",n]]);export{u as __pageData,f as default};
